local Players = game:GetService("Players") local UserInputService = game:GetService("UserInputService") local RunService = game:GetService("RunService") local player = Players.LocalPlayer local mouse = player:GetMouse() local camera = workspace.CurrentCamera local screenGui = Instance.new("ScreenGui") screenGui.Name = "UkradiBrainrotGui" screenGui.ResetOnSpawn = false screenGui.Parent = player:WaitForChild("PlayerGui") local mainButton = Instance.new("TextButton") mainButton.Size = UDim2.new(0, 260, 0, 80) mainButton.Position = UDim2.new(0.5, -130, 0, 45) mainButton.BackgroundColor3 = Color3.fromRGB(44, 112, 172) mainButton.Text = "" mainButton.AutoButtonColor = false mainButton.Parent = screenGui local mainCorner = Instance.new("UICorner") mainCorner.CornerRadius = UDim.new(0, 16) mainCorner.Parent = mainButton local uiStroke = Instance.new("UIStroke") uiStroke.Thickness = 3 uiStroke.ApplyStrokeMode = Enum.ApplyStrokeMode.Border uiStroke.Parent = mainButton local uIGradient = Instance.new("UIGradient") uIGradient.Color = ColorSequence.new({ColorSequenceKeypoint.new(0, Color3.fromRGB(0, 230, 255)), ColorSequenceKeypoint.new(1, Color3.fromRGB(255, 130, 50))}) uIGradient.Parent = uiStroke local iconFrame = Instance.new("Frame") iconFrame.Size = UDim2.new(0, 36, 0, 26) iconFrame.Position = UDim2.new(0, 20, 0.5, -13) iconFrame.BackgroundTransparency = 1 iconFrame.Parent = mainButton for i = 1, 3 do local bar = Instance.new("Frame") bar.Size = UDim2.new(1, 0, 0, 4) bar.Position = UDim2.new(0, 0, 0, (i-1) * 11) bar.BackgroundColor3 = Color3.fromRGB(255, 255, 255) bar.BorderSizePixel = 0 bar.Parent = iconFrame Instance.new("UICorner", bar).CornerRadius = UDim.new(1, 0) end local titleLabel = Instance.new("TextLabel") titleLabel.Size = UDim2.new(0, 180, 0, 30) titleLabel.Position = UDim2.new(0, 70, 0, 15) titleLabel.BackgroundTransparency = 1 titleLabel.Text = "UKRADI BRAINROT" titleLabel.TextColor3 = Color3.fromRGB(255, 255, 255) titleLabel.TextSize = 20 titleLabel.Font = Enum.Font.FredokaOne titleLabel.TextXAlignment = Enum.TextXAlignment.Left titleLabel.Parent = mainButton local subLabel = Instance.new("TextLabel") subLabel.Size = UDim2.new(0, 180, 0, 20) subLabel.Position = UDim2.new(0, 70, 0, 42) subLabel.BackgroundTransparency = 1 subLabel.Text = "Меню" subLabel.TextColor3 = Color3.fromRGB(230, 240, 255) subLabel.TextSize = 16 subLabel.Font = Enum.Font.SourceSans subLabel.TextXAlignment = Enum.TextXAlignment.Left subLabel.Parent = mainButton local menuFrame = Instance.new("ScrollingFrame") menuFrame.Size = UDim2.new(0, 260, 0, 144) menuFrame.Position = UDim2.new(0, 0, 1.1, 0) menuFrame.BackgroundColor3 = Color3.fromRGB(20, 28, 40) menuFrame.BackgroundTransparency = 0.15 menuFrame.Visible = false menuFrame.CanvasSize = UDim2.new(0, 0, 0, 290) menuFrame.ScrollBarThickness = 4 menuFrame.ScrollingDirection = Enum.ScrollingDirection.Y menuFrame.Parent = mainButton local menuCorner = Instance.new("UICorner") menuCorner.CornerRadius = UDim.new(0, 12) menuCorner.Parent = menuFrame local uiListLayout = Instance.new("UIListLayout") uiListLayout.Parent = menuFrame uiListLayout.HorizontalAlignment = Enum.HorizontalAlignment.Center uiListLayout.SortOrder = Enum.SortOrder.LayoutOrder uiListLayout.Padding = UDim.new(0, 6) local function createMenuButton(text, order, defaultColor) local btn = Instance.new("TextButton") btn.Size = UDim2.new(0, 240, 0, 42) btn.BackgroundColor3 = defaultColor or Color3.fromRGB(40, 52, 74) btn.Text = text btn.TextColor3 = Color3.fromRGB(255, 255, 255) btn.TextSize = 14 btn.Font = Enum.Font.SourceSansBold btn.LayoutOrder = order btn.Parent = menuFrame Instance.new("UICorner", btn).CornerRadius = UDim.new(0, 6) return btn end local clickTpButton = createMenuButton("ТП по клику: ВЫКЛ", 1, Color3.fromRGB(150, 30, 30)) local wallTpButton = createMenuButton("ТП сквозь стену (Вперед)", 2, Color3.fromRGB(60, 60, 60)) local flyButton = createMenuButton("Полёт (Мобильный): ВЫКЛ", 3, Color3.fromRGB(150, 30, 30)) local speedButton = createMenuButton("Скорость x12: ВЫКЛ", 4, Color3.fromRGB(150, 30, 30)) local jumpButton = createMenuButton("Бесконечный прыжок: ВЫКЛ", 5, Color3.fromRGB(150, 30, 30)) local antiKbButton = createMenuButton("Анти-Откидывание: ВЫКЛ", 6, Color3.fromRGB(150, 30, 30)) local espButton = createMenuButton("ВХ (Подсветка): ВЫКЛ", 7, Color3.fromRGB(150, 30, 30)) local dragging, dragInput, dragStart, startPos local function update(input) local delta = input.Position - dragStart mainButton.Position = UDim2.new(startPos.X.Scale, startPos.X.Offset + delta.X, startPos.Y.Scale, startPos.Y.Offset + delta.Y) end mainButton.InputBegan:Connect(function(input) local inputType = input.UserInputType if inputType == Enum.UserInputType.MouseButton1 or inputType == Enum.UserInputType.Touch then dragging = true dragStart = input.Position startPos = mainButton.Position input.Changed:Connect(function() if input.UserInputState == Enum.UserInputState.End then dragging = false end end) end end) mainButton.InputChanged:Connect(function(input) local inputType = input.UserInputType if inputType == Enum.UserInputType.MouseMovement or inputType == Enum.UserInputType.Touch then dragInput = input end end) UserInputService.InputChanged:Connect(function(input) if input == dragInput and dragging then update(input) end end) mainButton.MouseButton1Click:Connect(function() if not dragging then menuFrame.Visible = not menuFrame.Visible end end) local isClickTpEnabled = false local mouseConnection = nil local function disableClickTp() isClickTpEnabled = false clickTpButton.Text = "ТП по клику: ВЫКЛ" clickTpButton.BackgroundColor3 = Color3.fromRGB(150, 30, 30) if mouseConnection then mouseConnection:Disconnect() mouseConnection = nil end end clickTpButton.MouseButton1Click:Connect(function() if isClickTpEnabled then disableClickTp() else isClickTpEnabled = true clickTpButton.Text = "ТП по клику: ВКЛ" clickTpButton.BackgroundColor3 = Color3.fromRGB(30, 150, 30) mouseConnection = mouse.Button1Down:Connect(function() local character = player.Character if character and character:FindFirstChild("HumanoidRootPart") then local hitPos = mouse.Hit.Position character.HumanoidRootPart.CFrame = CFrame.new(hitPos + Vector3.new(0, 3, 0)) end end) end end) wallTpButton.MouseButton1Click:Connect(function() local character = player.Character if character and character:FindFirstChild("HumanoidRootPart") then local rootPart = character.HumanoidRootPart rootPart.CFrame = rootPart.CFrame + (rootPart.CFrame.LookVector * 15) end end) local isFlying = false local flyConnection = nil local bVelocity, bGyro local function disableFly() isFlying = false flyButton.Text = "Полёт (Мобильный): ВЫКЛ" flyButton.BackgroundColor3 = Color3.fromRGB(150, 30, 30) if flyConnection then flyConnection:Disconnect() flyConnection = nil end if bVelocity then bVelocity:Destroy() end if bGyro then bGyro:Destroy() end if player.Character and player.Character:FindFirstChildOfClass("Humanoid") then player.Character.Humanoid.PlatformStand = false end end flyButton.MouseButton1Click:Connect(function() if isFlying then disableFly() else isFlying = true flyButton.Text = "Полёт (Мобильный): ВКЛ" flyButton.BackgroundColor3 = Color3.fromRGB(30, 150, 30) local character = player.Character if not character or not character:FindFirstChild("HumanoidRootPart") then return end local rootPart = character.HumanoidRootPart local humanoid = character:FindFirstChildOfClass("Humanoid") humanoid.PlatformStand = true bGyro = Instance.new("BodyGyro") bGyro.P = 9e4 bGyro.maxTorque = Vector3.new(9e9, 9e9, 9e9) bGyro.cframe = rootPart.CFrame bGyro.Parent = rootPart bVelocity = Instance.new("BodyVelocity") bVelocity.maxForce = Vector3.new(9e9, 9e9, 9e9) bVelocity.Parent = rootPart flyConnection = RunService.RenderStepped:Connect(function() if character and rootPart and humanoid then bGyro.cframe = camera.CFrame local moveDir = humanoid.MoveDirection if moveDir.Magnitude > 0 then local camDir = camera.CFrame.LookVector bVelocity.velocity = camDir * 60 else bVelocity.velocity = Vector3.new(0, 0, 0) end end end) end end) local isSpeedEnabled = false local speedConnection = nil local function disableSpeed() isSpeedEnabled = false speedButton.Text = "Скорость x12: ВЫКЛ" speedButton.BackgroundColor3 = Color3.fromRGB(150, 30, 30) if speedConnection then speedConnection:Disconnect() speedConnection = nil end if player.Character and player.Character:FindFirstChildOfClass("Humanoid") then player.Character.Humanoid.WalkSpeed = 16 end end speedButton.MouseButton1Click:Connect(function() if isSpeedEnabled then disableSpeed() else isSpeedEnabled = true speedButton.Text = "Скорость x12: ВКЛ" speedButton.BackgroundColor3 = Color3.fromRGB(30, 150, 30) speedConnection = RunService.Heartbeat:Connect(function() local character = player.Character if character and character:FindFirstChildOfClass("Humanoid") then character.Humanoid.WalkSpeed = 16 * 12 end end) end end) local isInfJumpEnabled = false local jumpConnection = nil local function disableInfJump() isInfJumpEnabled = false jumpButton.Text = "Бесконечный прыжок: ВЫКЛ" jumpButton.BackgroundColor3 = Color3.fromRGB(150, 30, 30) if jumpConnection then jumpConnection:Disconnect() jumpConnection = nil end end jumpButton.MouseButton1Click:Connect(function() if isInfJumpEnabled then disableInfJump() else isInfJumpEnabled = true jumpButton.Text = "Бесконечный прыжок: ВКЛ" jumpButton.BackgroundColor3 = Color3.fromRGB(30, 150, 30) jumpConnection = UserInputService.JumpRequest:Connect(function() local character = player.Character if character and character:FindFirstChildOfClass("Humanoid") then character.Humanoid:ChangeState(Enum.HumanoidStateType.Jumping) end end) end end) local isAntiKbEnabled = false local antiKbConnection = nil local function disableAntiKb() isAntiKbEnabled = false antiKbButton.Text = "Анти-Откидывание: ВЫКЛ" antiKbButton.BackgroundColor3 = Color3.fromRGB(150, 30, 30) if antiKbConnection then antiKbConnection:Disconnect() antiKbConnection = nil end end antiKbButton.MouseButton1Click:Connect(function() if isAntiKbEnabled then disableAntiKb() else isAntiKbEnabled = true antiKbButton.Text = "Анти-Откидывание: ВКЛ" antiKbButton.BackgroundColor3 = Color3.fromRGB(30, 150, 30) antiKbConnection = RunService.Heartbeat:Connect(function() local character = player.Character if character and character:FindFirstChild("HumanoidRootPart") then local root = character.HumanoidRootPart for _, child in pairs(root:GetChildren()) do local cClass = child.ClassName if cClass == "BodyVelocity" or cClass == "LinearVelocity" or cClass == "BodyForce" or cClass == "VectorForce" then if child ~= bVelocity then child:Destroy() end end end end end) end end) local isEspEnabled = false local espHighlights = {} local function removeEsp() for _, highlight in pairs(espHighlights) do if highlight then highlight:Destroy() end end espHighlights = {} end local function applyEsp() for _, p in pairs(Players:GetPlayers()) do if p ~= player and p.Character then if not espHighlights[p] or not espHighlights[p].Parent then local highlight = Instance.new("Highlight") highlight.FillColor = Color3.fromRGB(255, 0, 0) highlight.OutlineColor = Color3.fromRGB(255, 255, 255) highlight.FillTransparency = 0.5 highlight.OutlineTransparency = 0 highlight.Adornee = p.Character highlight.Parent = p.Character espHighlights[p] = highlight end end end end local function disableEsp() isEspEnabled = false espButton.Text = "ВХ (Подсветка): ВЫКЛ" espButton.BackgroundColor3 = Color3.fromRGB(150, 30, 30) removeEsp() end espButton.MouseButton1Click:Connect(function() if isEspEnabled then disableEsp() else isEspEnabled = true espButton.Text = "ВХ (Подсветка): ВКЛ" espButton.BackgroundColor3 = Color3.fromRGB(30, 150, 30) RunService.Heartbeat:Connect(function() if isEspEnabled then applyEsp() end end) end end) player.CharacterAdded:Connect(function() disableClickTp() disableFly() disableSpeed() disableInfJump() disableAntiKb() disableEsp() end)
